// Fusionner les inputs : formulaire ou planification
const items = $input.all();
const item = items[0]?.json || {};

// Déterminer la source
const isForm = item['Cible réseau (IP ou domaine)'] !== undefined;

const network = isForm
  ? (item['Cible réseau (IP ou domaine)'] || 'scanme.nmap.org')
  : 'scanme.nmap.org';

const emailTo = isForm
  ? (item['Email destinataire du rapport'] || process.env.DEFAULT_REPORT_EMAIL)
  : process.env.DEFAULT_REPORT_EMAIL;

const portRange = isForm
  ? (item['Plage de ports à scanner'] || '1-1000')
  : '1-1000';

const timestamp = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);

return [{
  json: {
    network,
    emailTo,
    portRange,
    timestamp,
    tempDir: '/tmp/vulnscan',
    source: isForm ? 'form' : 'scheduler'
  }
}];

const nmapData = $input.first().json;
let raw = nmapData.stdout || '{"host":[]}';

// Si raw est déjà un objet, on le garde, sinon on le parse
let parsed;
if (typeof raw === 'string') {
    try {
        parsed = JSON.parse(raw);
    } catch (e) {
        parsed = { host: [] };
    }
} else {
    parsed = raw;
}

const hosts = parsed.host || [];
const network = $('1. Préparer les Paramètres').first().json.network;
const timestamp = $('1. Préparer les Paramètres').first().json.timestamp;
const tempDir = $('1. Préparer les Paramètres').first().json.tempDir;

const openPorts = [];

// Parcourir les hosts
for (let i = 0; i < hosts.length; i++) {
    const host = hosts[i];

    // Vérifier si host existe
    if (!host) continue;

    // Accéder aux ports de façon sécurisée
    const portsObj = host.ports || {};
    const portList = portsObj.port || [];

    for (let j = 0; j < portList.length; j++) {
        const port = portList[j];
        if (port && port.portid) {
            openPorts.push(parseInt(port.portid, 10));
        }
    }
}

console.log('Open ports:', JSON.stringify(openPorts));

// Déterminer les ports HTTP/HTTPS
let hasHTTP = false;
let hasHTTPS = false;
let httpPort = 80;
let httpsPort = 443;

const httpPorts = [80, 8080, 8000, 8888, 3000, 5000];
const httpsPorts = [443, 8443, 4443, 8443];

for (let k = 0; k < openPorts.length; k++) {
    const port = openPorts[k];

    if (httpPorts.includes(port)) {
        hasHTTP = true;
        httpPort = port;
    }
    if (httpsPorts.includes(port)) {
        hasHTTPS = true;
        httpsPort = port;
    }
}

// Vérifier aussi dans les services détectés pour plus de précision
for (let i = 0; i < hosts.length; i++) {
    const host = hosts[i];
    if (!host || !host.ports || !host.ports.port) continue;

    for (let j = 0; j < host.ports.port.length; j++) {
        const port = host.ports.port[j];
        if (!port || !port.service) continue;

        const serviceName = (port.service.name || '').toLowerCase();
        const portNum = parseInt(port.portid, 10);

        if (serviceName.includes('http') && !serviceName.includes('https')) {
            hasHTTP = true;
            httpPort = portNum;
        }
        if (serviceName.includes('https') || serviceName.includes('ssl')) {
            hasHTTPS = true;
            httpsPort = portNum;
        }
    }
}

console.log('hasHTTP:', hasHTTP, '| hasHTTPS:', hasHTTPS, '| httpPort:', httpPort, '| httpsPort:', httpsPort);

return [{
    json: {
        stdout: nmapData.stdout,
        network: network,
        timestamp: timestamp,
        tempDir: tempDir,
        openPorts: openPorts,
        hasHTTP: hasHTTP,
        hasHTTPS: hasHTTPS,
        httpPort: httpPort,
        httpsPort: httpsPort
    }
}];

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const portsData = $('Extraire Ports Ouverts').first().json;
const network = portsData.network;
const timestamp = portsData.timestamp;
const httpPort = portsData.httpPort || 80;
const httpsPort = portsData.httpsPort || 443;
const hasHTTPS = portsData.hasHTTPS || false;
const tempDir = '/tmp/vulnscan';
const wordlist = '/tmp/vulnscan/wordlist.txt';
const outFile = path.join(tempDir, `gobuster_${timestamp}.txt`);

try {
    execSync('which gobuster', { encoding: 'utf-8' });
} catch (e) {
    return [{ json: { gobusterResults: [], error: 'Gobuster not found' } }];
}

// Download wordlist if missing
if (!fs.existsSync(wordlist)) {
    try {
        execSync(`wget -q -O ${wordlist} https://raw.githubusercontent.com/danielmiessler/SecLists/master/Discovery/Web-Content/common.txt`,
            { encoding: 'utf-8', timeout: 30000 });
    } catch(e) {
        return [{ json: { gobusterResults: [], error: 'Failed to download wordlist' } }];
    }
}

// Always use HTTPS target since server redirects HTTP->HTTPS
const target = hasHTTPS
    ? `https://${network}:${httpsPort}`
    : `http://${network}:${httpPort}`;

console.log('Gobuster target:', target);

try {
    // First probe: check what status codes the server returns for non-existent paths
    let probeStatus = '404';
    try {
        const probe = execSync(
            `curl -sk -o /dev/null -w "%{http_code}" "${target}/this-path-should-not-exist-xyz123"`,
            { encoding: 'utf-8', timeout: 10000 }
        ).trim();
        probeStatus = probe;
        console.log('Server returns for non-existent paths:', probeStatus);
    } catch(e) {}

    // Build exclusion list based on probe result
    // Always exclude 301,302 (redirects). Add probe status if not 404.
    let excludeCodes = '301,302';
    if (probeStatus !== '404' && probeStatus !== '200') {
        excludeCodes += ',' + probeStatus;
    }

    // -k = ignore SSL cert errors, --random-agent = avoid blocking
    const cmd = `gobuster dir -u "${target}" -w "${wordlist}" -o "${outFile}" -t 15 -q --no-error --timeout 15s -b "${excludeCodes}" -k --random-agent 2>/dev/null`;
    console.log('CMD:', cmd);
    console.log('Excluded status codes:', excludeCodes);

    try {
        execSync(cmd, { encoding: 'utf-8', timeout: 180000, shell: '/bin/bash' });
    } catch(e) {
        console.log('Gobuster stopped:', e.message.substring(0, 100));
    }

    let gobusterResults = [];
    if (fs.existsSync(outFile)) {
        const content = fs.readFileSync(outFile, 'utf-8');
        console.log('Gobuster raw output length:', content.length);
        console.log('First 500 chars:', content.substring(0, 500));

        for (const line of content.split('\n').filter(l => l.trim())) {
            // Match both old and new gobuster output formats
            const m = line.match(/^(\S+)\s+\(Status:\s*(\d+)\)(?:\s+\[Size:\s*(\d+)\])?/)
                   || line.match(/^(\S+)\s+(\d{3})/);
            if (m) {
                gobusterResults.push({
                    tool: 'gobuster',
                    type: 'directory',
                    path: m[1],
                    status: m[2],
                    size: m[3] || ''
                });
            }
        }
    } else {
        console.log('Output file not created:', outFile);
    }

    console.log(`Gobuster found ${gobusterResults.length} paths`);

    if (gobusterResults.length === 0) {
        gobusterResults.push({
            tool: 'gobuster', type: 'info',
            path: target, status: 'N/A',
            size: 'No paths found — server may require authentication or block directory scanning'
        });
    }

    return [{ json: { gobusterResults } }];

} catch (error) {
    console.error('Gobuster error:', error.message);
    return [{ json: { gobusterResults: [], error: error.message } }];
}

const { execSync } = require('child_process');

const portsData = $('Extraire Ports Ouverts').first().json;
const network = portsData.network;
const httpsPort = portsData.httpsPort || 443;

console.log('SSLScan target:', network + ':' + httpsPort);

var raw = '';
try {
    var cmd = `sslscan --no-colour ${network}:${httpsPort}`;
    console.log('CMD:', cmd);
    raw = execSync(cmd, { encoding: 'utf-8', timeout: 60000 });
} catch(e) {
    raw = (e.stdout || '') + (e.stderr || '');
    console.log('SSLScan error:', e.message.substring(0, 80));
}

console.log('SSLScan output length:', raw.length);
if (raw.length > 0) console.log('First 300 chars:', raw.substring(0, 300));

var sslResults = [];

// sslscan actual output format: "SSLv2     disabled" or "TLSv1.0   enabled"
// Check protocols
if (raw.match(/SSLv2\s+enabled/i))     sslResults.push({ tool:'sslscan', severity:'CRITICAL', issue:'SSLv2 enabled', recommendation:'Disable SSLv2 immediately - it is broken' });
if (raw.match(/SSLv3\s+enabled/i))     sslResults.push({ tool:'sslscan', severity:'HIGH',     issue:'SSLv3 enabled (POODLE vulnerability)', recommendation:'Disable SSLv3' });
if (raw.match(/TLSv1\.0\s+enabled/i)) sslResults.push({ tool:'sslscan', severity:'MEDIUM',   issue:'TLS 1.0 enabled', recommendation:'Disable TLS 1.0, use TLS 1.2+' });
if (raw.match(/TLSv1\.1\s+enabled/i)) sslResults.push({ tool:'sslscan', severity:'MEDIUM',   issue:'TLS 1.1 enabled', recommendation:'Disable TLS 1.1, use TLS 1.2+' });

// Check weak ciphers
if (raw.match(/DES-CBC3/i))            sslResults.push({ tool:'sslscan', severity:'MEDIUM', issue:'Weak cipher: 3DES (SWEET32)', recommendation:'Disable 3DES cipher suite' });
if (raw.match(/\bRC4\b/i))            sslResults.push({ tool:'sslscan', severity:'HIGH',   issue:'Weak cipher: RC4', recommendation:'Disable RC4 cipher suite' });
if (raw.match(/\bNULL\b/i))           sslResults.push({ tool:'sslscan', severity:'CRITICAL', issue:'NULL cipher detected', recommendation:'Disable NULL cipher suites immediately' });
if (raw.match(/EXPORT/i))              sslResults.push({ tool:'sslscan', severity:'HIGH',   issue:'EXPORT grade cipher detected', recommendation:'Disable EXPORT cipher suites' });
if (raw.match(/anon/i))                sslResults.push({ tool:'sslscan', severity:'HIGH',   issue:'Anonymous cipher detected', recommendation:'Disable anonymous cipher suites' });

// Check certificate issues
if (raw.match(/expired/i))             sslResults.push({ tool:'sslscan', severity:'HIGH',   issue:'SSL certificate has expired', recommendation:'Renew SSL certificate immediately' });
if (raw.match(/self.?signed/i))        sslResults.push({ tool:'sslscan', severity:'MEDIUM', issue:'Self-signed certificate', recommendation:'Use a certificate from a trusted CA' });
if (raw.match(/not trusted/i))         sslResults.push({ tool:'sslscan', severity:'MEDIUM', issue:'Certificate not trusted', recommendation:'Use a certificate from a trusted CA' });

// Check Heartbleed
if (raw.match(/heartbleed.*vulnerable/i)) sslResults.push({ tool:'sslscan', severity:'CRITICAL', issue:'Heartbleed vulnerability detected!', recommendation:'Patch OpenSSL immediately' });

// Check Fallback SCSV
if (raw.match(/does not support.*fallback/i)) sslResults.push({ tool:'sslscan', severity:'MEDIUM', issue:'TLS Fallback SCSV not supported', recommendation:'Enable TLS Fallback SCSV to prevent downgrade attacks' });

// If output received but no issues found — server is secure
if (sslResults.length === 0 && raw.length > 200) {
    // Extract TLS versions actually enabled for informational output
    const tlsEnabled = [];
    if (raw.match(/TLSv1\.2\s+enabled/i)) tlsEnabled.push('TLS 1.2');
    if (raw.match(/TLSv1\.3\s+enabled/i)) tlsEnabled.push('TLS 1.3');

    sslResults.push({
        tool: 'sslscan',
        severity: 'INFO',
        issue: `SSL/TLS configuration is secure. Protocols enabled: ${tlsEnabled.join(', ') || 'TLS 1.2+'}`,
        recommendation: 'No major SSL/TLS issues detected. Keep certificates and software updated.'
    });
}

// If no output at all
if (raw.length < 50) {
    sslResults.push({
        tool: 'sslscan',
        severity: 'ERROR',
        issue: 'SSLScan produced no output',
        recommendation: 'Check if sslscan is installed and target is reachable on port ' + httpsPort
    });
}

console.log('SSLScan found ' + sslResults.length + ' results');
return [{ json: { sslResults } }];

const { execSync } = require('child_process');
const fs = require('fs');

const portsData = $('Extraire Ports Ouverts').first().json;
const network = portsData.network;
const hasHTTPS = portsData.hasHTTPS || false;
const httpsPort = portsData.httpsPort || 443;
const httpPort = portsData.httpPort || 80;
const timestamp = portsData.timestamp;
const tempDir = '/tmp/vulnscan';
const outFile = `${tempDir}/whatweb_${timestamp}.json`;

// Use HTTPS if available
const target = hasHTTPS
    ? `https://${network}:${httpsPort}`
    : `http://${network}:${httpPort}`;

console.log('WhatWeb target:', target);

if (!fs.existsSync(tempDir)) fs.mkdirSync(tempDir, { recursive: true });

let whatwebResults = [];

try {
    // Write JSON output to a file (more reliable than stdout with --log-json=-)
    // --no-errors suppresses connection errors, -a 3 = aggressive scan
    const cmd = `whatweb -a 3 --follow-redirect=always --log-json="${outFile}" "${target}"`;
    console.log('CMD:', cmd);

    try {
        execSync(cmd, { encoding: 'utf-8', timeout: 60000, shell: '/bin/bash' });
    } catch(e) {
        console.log('WhatWeb finished:', e.message.substring(0, 100));
    }

    if (fs.existsSync(outFile)) {
        const raw = fs.readFileSync(outFile, 'utf-8').trim();
        console.log('WhatWeb output length:', raw.length);
        console.log('First 300 chars:', raw.substring(0, 300));

        // WhatWeb JSON output: one JSON object per line
        for (const line of raw.split('\n').filter(l => l.trim())) {
            try {
                const entry = JSON.parse(line);
                const tgt = entry.target || network;
                const plugins = entry.plugins || {};

                for (const [pluginName, pluginData] of Object.entries(plugins)) {
                    whatwebResults.push({
                        tool: 'whatweb',
                        type: 'technology',
                        target: tgt,
                        technology: pluginName,
                        version: (pluginData.version || []).join(', ') || 'detected',
                        string: (pluginData.string || []).join(', ')
                    });
                }
            } catch(e) {
                console.log('JSON parse error on line:', line.substring(0, 80));
            }
        }
    } else {
        console.log('Output file not created, trying stdout fallback...');

        // Fallback: capture stdout directly
        let stdout = '';
        try {
            stdout = execSync(
                `whatweb -a 3 --follow-redirect=always --log-json=- "${target}" 2>&1`,
                { encoding: 'utf-8', timeout: 60000, shell: '/bin/bash' }
            );
        } catch(e) {
            stdout = e.stdout || '';
        }

        console.log('Stdout length:', stdout.length);
        for (const line of stdout.split('\n').filter(l => l.trim() && l.startsWith('['))) {
            try {
                const entry = JSON.parse(line);
                const plugins = entry.plugins || {};
                for (const [pluginName, pluginData] of Object.entries(plugins)) {
                    whatwebResults.push({
                        tool: 'whatweb', type: 'technology',
                        target: entry.target || network,
                        technology: pluginName,
                        version: (pluginData.version || []).join(', ') || 'detected',
                        string: (pluginData.string || []).join(', ')
                    });
                }
            } catch(e) {}
        }
    }

    console.log(`WhatWeb detected ${whatwebResults.length} technologies`);

    if (whatwebResults.length === 0) {
        whatwebResults.push({
            tool: 'whatweb', type: 'info',
            target: target, technology: 'No technologies detected',
            version: '', string: 'WhatWeb ran but found no identifiable technologies'
        });
    }

    return [{ json: { whatwebResults } }];

} catch (error) {
    console.error('WhatWeb error:', error.message);
    return [{ json: { whatwebResults: [], error: error.message } }];
}

const allItems = $input.all();
const nmapData = $('Extraire Ports Ouverts').first().json;

let niktoResults = [], sslResults = [], 
    whatwebResults = [], gobusterResults = [], wpscanResults = [],hydraResults = []; 

for (const item of allItems) {
    const d = item.json;
    if (d.niktoResults !== undefined) niktoResults = d.niktoResults || [];
    if (d.sslResults !== undefined) sslResults = d.sslResults || [];
    if (d.whatwebResults !== undefined) whatwebResults = d.whatwebResults || [];
    if (d.gobusterResults !== undefined) gobusterResults = d.gobusterResults || [];
    if (d.wpscanResults !== undefined) wpscanResults = d.wpscanResults || [];
  if (d.hydraResults !== undefined) hydraResults = d.hydraResults || []; 
}

return [{ json: {
    stdout: nmapData.stdout,
    niktoResults,
    sslResults,
    whatwebResults,
    gobusterResults,
    wpscanResults,
    hydraResults// Ajouté
} }];

const mergerData = $('Merge Code').first().json;
const niktoItems = mergerData.niktoResults || [];
const sslItems = mergerData.sslResults || [];
const gobusterItems = mergerData.gobusterResults || [];
const whatwebItems = mergerData.whatwebResults || [];
const targetNetwork = $('1. Préparer les Paramètres').first().json.network;

console.log('Groq AI Analysis starting...');
console.log('Nikto:', niktoItems.length, '| SSL:', sslItems.length, '| Gobuster:', gobusterItems.length, '| WhatWeb:', whatwebItems.length);

const prompt = `Tu es un expert en cybersécurité offensive et défensive (OSCP, CEH).
Analyse ces résultats de scan de vulnérabilités pour la cible: ${targetNetwork}

=== FINDINGS BRUTS ===
NIKTO (vulnérabilités web): ${JSON.stringify(niktoItems.map(n => n.msg))}
SSL/TLS: ${JSON.stringify(sslItems.map(s => ({issue: s.issue, severity: s.severity})))}
GOBUSTER (répertoires): ${JSON.stringify(gobusterItems.map(g => ({path: g.path, status: g.status})))}
WHATWEB (technologies): ${JSON.stringify(whatwebItems.map(w => ({tech: w.technology, version: w.version})))}

Retourne UNIQUEMENT ce JSON valide (sans markdown ni backticks):
{
  "resume_executif": "Paragraphe professionnel en français décrivant la posture de sécurité globale, les risques principaux et les priorités d'action",
  "risque_global": "CRITIQUE",
  "findings_valides": [
    {
      "id": "F001",
      "titre": "titre court du finding",
      "description": "explication technique claire en français",
      "faux_positif": false,
      "severite": "CRITICAL",
      "cvss_score": 9.8,
      "cvss_vector": "CVSS:3.1/AV:N/AC:L/PR:N/UI:N/S:U/C:H/I:H/A:H",
      "cves": ["CVE-2021-XXXXX"],
      "impact": "description de l'impact potentiel",
      "remediation": "étapes concrètes et précises pour corriger",
      "source": "nikto"
    }
  ],
  "stats": {
    "total_findings": 0,
    "critical": 0,
    "high": 0,
    "medium": 0,
    "low": 0,
    "info": 0,
    "faux_positifs_filtres": 0
  }
}`;

try {
    const response = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.groq.com/openai/v1/chat/completions',
        headers: {
            'Content-Type': 'application/json',
            'Authorization': 'Bearer VOTRE_CLE_GROQ_ICI'
        },
        body: JSON.stringify({
            model: 'llama-3.3-70b-versatile',
            max_tokens: 4096,
            temperature: 0.1,
            messages: [
                {
                    role: 'system',
                    content: 'Tu es un expert en cybersécurité. Tu retournes UNIQUEMENT du JSON valide, sans markdown, sans backticks, sans texte avant ou après.'
                },
                {
                    role: 'user',
                    content: prompt
                }
            ]
        }),
        timeout: 60000
    });

    const rawText = response.choices[0].message.content;
    console.log('Groq response length:', rawText.length);

    const cleanText = rawText.replace(/```json|```/g, '').trim();
    const aiAnalysis = JSON.parse(cleanText);

    console.log('AI findings:', aiAnalysis.findings_valides?.length);
    console.log('Risque global:', aiAnalysis.risque_global);

    return [{ json: {
        ...mergerData,
        aiAnalysis,
        aiSuccess: true
    }}];

} catch(error) {
    console.error('Groq API error:', error.message);
    return [{ json: {
        ...mergerData,
        aiAnalysis: {
            resume_executif: 'Analyse IA indisponible — vérifier la clé API Groq.',
            risque_global: 'INCONNU',
            findings_valides: [],
            stats: { total_findings: 0, critical: 0, high: 0, medium: 0, low: 0, info: 0, faux_positifs_filtres: 0 }
        },
        aiSuccess: false,
        aiError: error.message
    }}];
}

const raw = $input.first().json;
const nmapJson = raw.stdout ? JSON.parse(raw.stdout) : raw;

let services = [];
const hosts = nmapJson.host || [];

for (const host of hosts) {
    const ip = host.address?.[0]?.addr || 'unknown';
    const ports = host.ports?.port || [];

    for (const portObj of ports) {
        if (portObj.state?.state !== 'open') continue;
        const serviceObj = portObj.service || {};

        let cpe = '';
        if (Array.isArray(serviceObj.cpe) && serviceObj.cpe.length > 0) {
            const rawCpe = serviceObj.cpe[0];
            if (rawCpe.startsWith('cpe:/')) {
                cpe = 'cpe:2.3:' + rawCpe.slice(5).replace(/\//g, ':');
                const parts = cpe.split(':');
                while (parts.length < 13) parts.push('*');
                cpe = parts.slice(0, 13).join(':');
            } else {
                cpe = rawCpe;
            }
        }

        services.push({
            ip, port: portObj.portid, protocol: portObj.protocol,
            service: serviceObj.name || 'unknown',
            product: serviceObj.product || '',
            version: serviceObj.version || '',
            cpe,
            serviceKey: `${ip}:${portObj.portid}`
        });
    }
}

console.log(`✓ Parsed ${services.length} open services`);
return [{ json: { services } }];

const services = $input.first().json.services;
const enriched = [];

console.log('=== CVE ENRICHMENT START ===');
console.log(`Processing ${services.length} services`);

for (let i = 0; i < services.length; i++) {
    const service = services[i];
    const base = { ...service };

    if (!base.cpe || base.cpe.trim() === '' || base.cpe === ':') {
        enriched.push({ ...base, cveId: 'N/A', cveSummary: 'No CPE available', cvssScore: 0, severity: 'INFO' });
        continue;
    }

    try {
        const vendor = base.cpe.split(':')[3] || '';
        const product = base.cpe.split(':')[4] || '';
        const version = base.cpe.split(':')[5] || '';

        let apiUrl = version && version !== '*'
            ? `https://services.nvd.nist.gov/rest/json/cves/2.0?cpeName=${encodeURIComponent(base.cpe)}&resultsPerPage=20`
            : `https://services.nvd.nist.gov/rest/json/cves/2.0?keywordSearch=${encodeURIComponent(vendor + ' ' + product)}&resultsPerPage=20`;

        console.log(`[${i+1}/${services.length}] Querying: ${base.cpe}`);

        const response = await this.helpers.httpRequest({
            method: 'GET',
            url: apiUrl,
            timeout: 30000,
            headers: { 'User-Agent': 'n8n-vulnerability-scanner/2.0' }
        });

        const vulnerabilities = response.vulnerabilities || [];
        console.log(`-> Found ${vulnerabilities.length} CVEs`);

        if (vulnerabilities.length === 0) {
            enriched.push({ ...base, cveId: 'N/A', cveSummary: 'No known vulnerabilities found', cvssScore: 0, severity: 'INFO' });
        } else {
            for (const vuln of vulnerabilities) {
                const cve = vuln.cve || {};
                const cveId = cve.id || 'UNKNOWN';
                const cveSummary = (cve.descriptions || []).find(d => d.lang === 'en')?.value || 'No description';
                const metrics = cve.metrics || {};
                const metricV31 = metrics.cvssMetricV31?.[0];
                const metricV30 = metrics.cvssMetricV30?.[0];
                const metricV2 = metrics.cvssMetricV2?.[0];
                const bestMetric = metricV31 || metricV30 || metricV2;
                const cvssData = bestMetric?.cvssData || {};
                const cvssScore = cvssData.baseScore || 0;
                const severity = cvssData.baseSeverity || metricV2?.baseSeverity || 'UNKNOWN';
                const publishedDate = cve.published || 'N/A';

                enriched.push({ ...base, cveId, cveSummary, cvssScore, severity, publishedDate });
            }
        }

    } catch (error) {
        console.error(`Error: ${error.message}`);
        enriched.push({ ...base, cveId: 'N/A', cveSummary: `API Error: ${error.message}`, cvssScore: 0, severity: 'ERROR' });
    }

    if (i < services.length - 1) {
        console.log('Waiting 6s...');
        await new Promise(r => setTimeout(r, 6000));
    }
}

