const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const htmlContent = $input.first().json.html;
const filename = $input.first().json.filename;
const timestamp = $input.first().json.timestamp;

const tempDir = '/tmp/vulnscan';
const htmlFile = filename;
const pdfFile = filename.replace('.html', '.pdf');
const htmlPath = path.join(tempDir, htmlFile);
const pdfPath = path.join(tempDir, pdfFile);

console.log('Creating PDF report...');
console.log('HTML:', htmlPath);
console.log('PDF:', pdfPath);

try {
    if (!fs.existsSync(tempDir)) {
        fs.mkdirSync(tempDir, { recursive: true, mode: 0o755 });
    }

    // Vérifier wkhtmltopdf
    try {
        execSync('which wkhtmltopdf', { encoding: 'utf-8' });
    } catch (e) {
        throw new Error('wkhtmltopdf not found. Installez avec: sudo apt-get install wkhtmltopdf');
    }

    fs.writeFileSync(htmlPath, htmlContent, 'utf-8');
    console.log('✓ HTML saved');

    const cmd = `wkhtmltopdf "${htmlPath}" "${pdfPath}"`;
    execSync(cmd, { 
        encoding: 'utf-8',
        cwd: tempDir,
        timeout: 60000,
        shell: '/bin/bash'
    });

    console.log('✓ PDF generation complete');

    if (fs.existsSync(pdfPath)) {
        const pdfBuffer = fs.readFileSync(pdfPath);
        const size = pdfBuffer.length;

        console.log(`✓ PDF created: ${(size / 1024).toFixed(2)} KB`);

        return [{
            json: {
                success: true,
                pdfPath: pdfPath,
                fileSize: size,
                filename: pdfFile,
                message: `✅ PDF Report generated successfully! (${(size / 1024).toFixed(2)} KB)`
            },
            binary: {
                data: {
                    data: pdfBuffer.toString('base64'),
                    mimeType: 'application/pdf',
                    fileName: pdfFile
                }
            }
        }];
    } else {
        throw new Error('PDF file was not created');
    }

} catch (error) {
    console.error('❌ Error:', error.message);
    throw new Error(`PDF generation failed: ${error.message}`);
}

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const network = $('1. Préparer les Paramètres').first().json.network;
const timestamp = $('1. Préparer les Paramètres').first().json.timestamp;
const tempDir = $('1. Préparer les Paramètres').first().json.tempDir;
const portRange = $('1. Préparer les Paramètres').first().json.portRange || '22,80,443,8080,8443';
const xmlPath = path.join(tempDir, `nmap_${timestamp}.xml`);

// Créer le répertoire temporaire
if (!fs.existsSync(tempDir)) {
    fs.mkdirSync(tempDir, { recursive: true, mode: 0o755 });
}

console.log('Nmap target:', network, '| ports:', portRange);

try {
    // Vérifier si nmap est installé
    try {
        execSync('which nmap', { encoding: 'utf-8' });
    } catch (e) {
        throw new Error('nmap n\'est pas installé. Installez-le avec: sudo apt-get install nmap');
    }

    const nmapCmd = `nmap -sV --version-intensity 3 -p ${portRange} -T4 --max-retries 1 -oX "${xmlPath}" ${network}`;
    console.log('CMD:', nmapCmd);

    try {
        execSync(nmapCmd, { 
            encoding: 'utf-8', 
            timeout: 45000,
            shell: '/bin/bash'
        });
        console.log('Nmap complete');
    } catch(e) {
        console.log('Nmap exit:', e.message.substring(0, 100));
    }

    if (!fs.existsSync(xmlPath)) {
        return [{ json: { stdout: JSON.stringify({ host: [] }) } }];
    }

    const xmlContent = fs.readFileSync(xmlPath, 'utf-8');
    console.log('XML size:', xmlContent.length);

    const hosts = [];
    const hostBlocks = xmlContent.match(/<host[\s\S]*?<\/host>/g) || [];

    for (const hostBlock of hostBlocks) {
        const addrMatch = hostBlock.match(/<address addr="([^"]+)" addrtype="ipv4"/);
        if (!addrMatch) continue;
        const ip = addrMatch[1];
        const ports = [];
        const portBlocks = hostBlock.match(/<port\s[\s\S]*?<\/port>/g) || [];

        for (const portBlock of portBlocks) {
            const stateMatch = portBlock.match(/state="([^"]+)"/);
            if (!stateMatch || stateMatch[1] !== 'open') continue;
            const portidMatch = portBlock.match(/portid="([^"]+)"/);
            const protocolMatch = portBlock.match(/protocol="([^"]+)"/);
            const nameMatch = portBlock.match(/name="([^"]+)"/);
            const productMatch = portBlock.match(/product="([^"]+)"/);
            const versionMatch = portBlock.match(/<service[^>]*version="([^"]+)"/);
            const cpeMatch = portBlock.match(/<cpe>([^<]+)<\/cpe>/);

            ports.push({
                portid: portidMatch ? portidMatch[1] : '0',
                protocol: protocolMatch ? protocolMatch[1] : 'tcp',
                state: { state: 'open' },
                service: {
                    name: nameMatch ? nameMatch[1] : 'unknown',
                    product: productMatch ? productMatch[1] : '',
                    version: versionMatch ? versionMatch[1] : '',
                    cpe: cpeMatch ? [cpeMatch[1]] : []
                }
            });
        }
        hosts.push({ 
            address: [{ addr: ip, addrtype: 'ipv4' }], 
            ports: { port: ports } 
        });
    }

    console.log(`Found ${hosts.length} hosts, ${hosts.reduce((a, h) => a + h.ports.port.length, 0)} open ports`);
    return [{ json: { stdout: JSON.stringify({ host: hosts }) } }];

} catch (error) {
    console.error('Nmap fatal:', error.message);
    return [{ json: { stdout: JSON.stringify({ host: [] }), error: error.message } }];
}

