let niktoResults = [];

try {
    const protocol = hasHTTPS ? 'https' : 'http';
    const port = hasHTTPS ? httpsPort : httpPort;

    const cmd = `nikto -h ${protocol}://${network} -port ${port} -nointeractive -timeout 10 -maxtime 120 -Format csv -o ${outputFile} 2>/dev/null`;
    console.log('CMD:', cmd);

    try {
        await execPromise(cmd, { timeout: 150000, shell: '/bin/bash' });
    } catch(e) {
