                        method: 'GET',
                        url: `${protocol}://${network}`,
                        msg: cleanLine.substring(0, 300),
                        remediation: 'Review and patch accordingly'
                    });
                }
            }
        }
    }

    if (niktoResults.length === 0) {
        niktoResults.push({ tool: 'nikto', type: 'info', id: 'NO_ISSUES',
            msg: 'No vulnerabilities detected by Nikto',
            url: `${hasHTTPS ? 'https' : 'http'}://${network}` });
    }

    console.log(`Nikto found ${niktoResults.length} issues`);

} catch (error) {
    console.error('Nikto error:', error.message);
    niktoResults.push({ tool: 'nikto', type: 'error', id: 'SCAN_ERROR',
        msg: `Nikto scan error: ${error.message}`, url: network });
