const { exec } = require('child_process');
const util = require('util');
const execPromise = util.promisify(exec);
const fs = require('fs');

const network = $('Extraire Ports Ouverts').first().json.network;
const httpPort = $('Extraire Ports Ouverts').first().json.httpPort || 80;
const httpsPort = $('Extraire Ports Ouverts').first().json.httpsPort || 443;
const timestamp = $('Extraire Ports Ouverts').first().json.timestamp;
const tempDir = '/tmp/vulnscan';
const outputFile = `${tempDir}/wpscan_${timestamp}.json`;

console.log('🔍 Checking for WordPress on:', network);

let wpscanResults = [];
let isWordPress = false;

try {
    // D'abord, vérifier si WordPress est détecté par WhatWeb
    const whatwebResults = $('WhatWeb').first().json.whatwebResults || [];

    // Vérifier si WordPress est dans les technologies détectées
    for (const tech of whatwebResults) {
        if (tech.technology && tech.technology.toLowerCase().includes('wordpress')) {
            isWordPress = true;
            console.log('✅ WordPress detected!');
            break;
        }
    }

    // Vérification alternative avec curl (si WhatWeb n'a pas détecté)
    if (!isWordPress) {
        const urls = [
            `http://${network}:${httpPort}/wp-admin`,
            `https://${network}:${httpsPort}/wp-admin`,
            `http://${network}:${httpPort}/wp-login.php`,
            `https://${network}:${httpsPort}/wp-login.php`
        ];

        for (const url of urls) {
            try {
                const cmd = `curl -s -o /dev/null -w "%{http_code}" ${url}`;
                const { stdout } = await execPromise(cmd, { timeout: 5000 });
                if (stdout.trim() === '200') {
                    isWordPress = true;
                    console.log(`✅ WordPress detected via ${url}`);
                    break;
                }
            } catch(e) {}
        }
    }

    // Si WordPress est détecté, lancer WPScan
    if (isWordPress) {
        console.log('🔬 Starting WPScan...');

        // Construire l'URL
        let url = '';
        if ($('Extraire Ports Ouverts').first().json.hasHTTPS) {
            url = `https://${network}:${httpsPort}`;
        } else {
            url = `http://${network}:${httpPort}`;
        }

        // Commande WPScan avec sortie JSON
        const cmd = `wpscan --url ${url} --format json --output ${outputFile} --no-banner --api-token jkBsASpvyd1xOBiafzEgSRNePQAoR0Dalzv0NYaIGOU`;
        // Note: Pour un scan complet, il faut un token API gratuit sur https://wpscan.com/register

        console.log('CMD:', cmd);

        try {
            await execPromise(cmd, { timeout: 300000, shell: '/bin/bash' });
            console.log('WPScan completed');
        } catch (e) {
            console.log('WPScan finished (may have findings)');
        }

        // Lire les résultats JSON
        if (fs.existsSync(outputFile)) {
            const content = fs.readFileSync(outputFile, 'utf-8');
            const data = JSON.parse(content);

            // Extraire les vulnérabilités
            if (data.vulnerabilities) {
                for (const [component, vulns] of Object.entries(data.vulnerabilities)) {
                    for (const vuln of vulns) {
                        wpscanResults.push({
                            tool: 'wpscan',
                            type: 'wordpress_vulnerability',
                            component: component,
                            id: vuln.id || vuln.cve || 'UNKNOWN',
                            severity: vuln.severity || getSeverityFromCVSS(vuln.cvss_score),
                            cvss_score: vuln.cvss_score || 0,
                            title: vuln.title || vuln.name || `Vulnerability in ${component}`,
                            description: vuln.description || vuln.references?.description || '',
                            remediation: vuln.fixed_in ? `Update to version ${vuln.fixed_in} or higher` : 'Apply security patch',
                            references: vuln.references || [],
                            url: url
                        });
                    }
                }
            }

            // Extraire les plugins vulnérables
            if (data.version && data.version.vulnerabilities) {
                for (const vuln of data.version.vulnerabilities) {
                    wpscanResults.push({
                        tool: 'wpscan',
                        type: 'wordpress_version',
                        component: `WordPress ${data.version.number}`,
                        id: vuln.id || 'UNKNOWN',
                        severity: vuln.severity || 'MEDIUM',
                        title: vuln.title,
                        description: vuln.description,
                        remediation: vuln.fixed_in ? `Update to WordPress ${vuln.fixed_in}` : 'Update WordPress to latest version',
                        references: vuln.references || []
                    });
                }
            }

            // Extraire les thèmes vulnérables
            if (data.themes && data.themes.length > 0) {
                for (const theme of data.themes) {
                    if (theme.vulnerabilities && theme.vulnerabilities.length > 0) {
                        for (const vuln of theme.vulnerabilities) {
                            wpscanResults.push({
                                tool: 'wpscan',
                                type: 'wordpress_theme',
                                component: `Theme: ${theme.name}`,
                                id: vuln.id || 'UNKNOWN',
                                severity: vuln.severity || 'MEDIUM',
                                title: vuln.title,
                                description: vuln.description,
                                remediation: vuln.fixed_in ? `Update theme to ${vuln.fixed_in}` : 'Update or remove vulnerable theme'
                            });
                        }
                    }
                }
            }

            // Extraire les plugins vulnérables
            if (data.plugins && data.plugins.length > 0) {
                for (const plugin of data.plugins) {
                    if (plugin.vulnerabilities && plugin.vulnerabilities.length > 0) {
                        for (const vuln of plugin.vulnerabilities) {
                            wpscanResults.push({
                                tool: 'wpscan',
                                type: 'wordpress_plugin',
                                component: `Plugin: ${plugin.name}`,
                                version: plugin.version,
                                id: vuln.id || 'UNKNOWN',
                                severity: vuln.severity || 'MEDIUM',
                                title: vuln.title,
                                description: vuln.description,
                                remediation: vuln.fixed_in ? `Update plugin to ${vuln.fixed_in}` : 'Update or remove vulnerable plugin'
                            });
                        }
                    }
                }
            }
        }

        console.log(`✅ WPScan found ${wpscanResults.length} issues`);

    } else {
        console.log('WordPress not detected, skipping WPScan');
        wpscanResults.push({
            tool: 'wpscan',
            type: 'info',
            id: 'NO_WORDPRESS',
            severity: 'info',
            description: 'WordPress not detected on this target',
            url: `http://${network}`
        });
    }

} catch (error) {
    console.error('❌ WPScan error:', error.message);
    wpscanResults.push({
        tool: 'wpscan',
        type: 'error',
        id: 'WPSCAN_ERROR',
        severity: 'info',
        description: `WPScan error: ${error.message}`,
        url: `http://${network}`
    });
}

// Fonction helper pour déterminer la sévérité
function getSeverityFromCVSS(score) {
    if (!score) return 'info';
    if (score >= 9.0) return 'critical';
    if (score >= 7.0) return 'high';
    if (score >= 4.0) return 'medium';
    if (score > 0) return 'low';
    return 'info';
}

return [{ json: { wpscanResults } }];

const { exec } = require('child_process');
const util = require('util');
const execPromise = util.promisify(exec);
const fs = require('fs');

const portsData = $('Extraire Ports Ouverts').first().json;
const network = portsData.network;
const openPorts = portsData.openPorts || [];
const timestamp = portsData.timestamp;
const hasHTTPS = portsData.hasHTTPS || false;
const httpsPort = portsData.httpsPort || 443;
const httpPort = portsData.httpPort || 80;
const tempDir = '/tmp/vulnscan';
const baseOutput = `${tempDir}/hydra_${timestamp}`;

console.log('Starting Hydra scan on:', network);
console.log('Open ports:', openPorts);

let hydraResults = [];

if (!fs.existsSync(tempDir)) fs.mkdirSync(tempDir, { recursive: true });

const commonPasswords = ['password','123456','admin','root','toor','qwerty','abc123','letmein','welcome','admin123','password123'];
const commonUsers = ['root','admin','user','test','ubuntu','user1'];

const passFile = `${tempDir}/passwords_${timestamp}.txt`;
const userFile = `${tempDir}/users_${timestamp}.txt`;
fs.writeFileSync(passFile, commonPasswords.join('\n'));
fs.writeFileSync(userFile, commonUsers.join('\n'));

// Build list of services to scan based on open ports
const servicesToScan = [];

if (openPorts.includes(22))   servicesToScan.push({ service: 'ssh',        port: 22,        ext: 'ssh' });
if (openPorts.includes(21))   servicesToScan.push({ service: 'ftp',        port: 21,        ext: 'ftp' });
if (openPorts.includes(3306)) servicesToScan.push({ service: 'mysql',      port: 3306,      ext: 'mysql' });
if (openPorts.includes(5432)) servicesToScan.push({ service: 'postgres',   port: 5432,      ext: 'postgres' });
if (openPorts.includes(3389)) servicesToScan.push({ service: 'rdp',        port: 3389,      ext: 'rdp' });

// HTTP / HTTPS - use correct protocol
if (hasHTTPS && openPorts.includes(httpsPort)) {
    servicesToScan.push({ service: 'https-get', port: httpsPort, ext: 'https', path: '/' });
} else if (openPorts.includes(httpPort)) {
    servicesToScan.push({ service: 'http-get',  port: httpPort,  ext: 'http',  path: '/' });
}

console.log('Services to brute-force:', servicesToScan.map(s => s.service).join(', ') || 'none');

if (servicesToScan.length === 0) {
    hydraResults.push({ tool: 'hydra', type: 'info', id: 'NO_SERVICES',
        severity: 'info', description: 'No brute-forceable services found on open ports', url: network });
    return [{ json: { hydraResults } }];
}

for (const target of servicesToScan) {
    console.log(`Brute-forcing ${target.service} on port ${target.port}...`);
    const outFile = `${baseOutput}.${target.ext}`;

    let cmd = '';
    if (target.service === 'https-get') {
        cmd = `hydra -L ${userFile} -P ${passFile} -o ${outFile} -f -v -I -s ${target.port} https-get://${network}${target.path}`;
    } else if (target.service === 'http-get') {
        cmd = `hydra -L ${userFile} -P ${passFile} -o ${outFile} -f -v -I http-get://${network}:${target.port}${target.path}`;
    } else {
        cmd = `hydra -L ${userFile} -P ${passFile} ${target.service}://${network}:${target.port} -t 4 -o ${outFile} -f -v -I`;
    }

    console.log('CMD:', cmd);
    try {
        await execPromise(cmd, { timeout: 120000, shell: '/bin/bash' });
    } catch(e) {
        console.log(`${target.service} finished:`, e.message.substring(0, 80));
    }

    // Read results from correct output file
    if (fs.existsSync(outFile)) {
        const content = fs.readFileSync(outFile, 'utf-8');
        for (const line of content.split('\n')) {
            const match = line.match(/host:\s*(\S+)\s+login:\s*(\S+)\s+password:\s*(.+)/i);
            if (match) {
                hydraResults.push({
                    tool: 'hydra', type: 'credential',
                    service: target.service, port: target.port,
                    host: match[1], username: match[2], password: match[3].trim(),
                    severity: 'critical',
                    description: `Weak credentials found for ${target.service} on port ${target.port}`,
                    remediation: `Change password for '${match[2]}' immediately. Use a strong unique password.`
                });
            }
        }
    }
}

// Cleanup temp files
try { fs.unlinkSync(passFile); fs.unlinkSync(userFile); } catch(e) {}

console.log(`Hydra found ${hydraResults.length} weak credentials`);

if (hydraResults.length === 0) {
    hydraResults.push({ tool: 'hydra', type: 'info', id: 'NO_WEAK_CREDENTIALS',
        severity: 'info', description: 'No weak credentials found', url: network });
}

return [{ json: { hydraResults } }];
